class Solution {
public:
    int countWinningSequences(string s) {
        const int MOD = 1e9 + 7;
        int n = s.size();
        vector<vector<long long>> dp(n, vector<long long>(3, 0));
        for (int j = 0; j < 3; ++j) {
            if (j != s[0] - 'F') {
                dp[0][j] = 1;
            }
        }
        for (int i = 1; i < n; ++i) {
            for (int j = 0; j < 3; ++j) {
                for (int k = 0; k < 3; ++k) {
                    if (k != j) {
                        int alice = s[i] - 'F';
                        int bob = j;
                        long long score = (alice == 0 && bob == 2) || (alice == 1 && bob == 0) || (alice == 2 && bob == 1) ? 1 : -1;
                        dp[i][j] = (dp[i][j] + dp[i - 1][k] * (score == 1 ? 1 : 0) + MOD) % MOD;
                    }
                }
            }
        }
        long long aliceScore = 0, bobScore = 0;
        for (int i = 0; i < n; ++i) {
            int alice = s[i] - 'F';
            for (int j = 0; j < 3; ++j) {
                int bob = j;
                if ((alice == 0 && bob == 2) || (alice == 1 && bob == 0) || (alice == 2 && bob == 1)) {
                    bobScore += dp[i][j];
                } else if ((alice == 0 && bob == 1) || (alice == 1 && bob == 2) || (alice == 2 && bob == 0)) {
                    aliceScore += dp[i][j];
                }
            }
        }
        return (bobScore > aliceScore ? bobScore - aliceScore : 0) % MOD;
    }
};
